messages.content:
Extract data from the following document based on the JSON schema.
Return null if the document does not contain information relevant to schema.
Return only the JSON with no explanation text.
The JSON schema is as follows:
{
  "type": "object",
  "title": "LiquidityAndCoverage",
  "required": [
    "liquidityCoverageRatios",
    "totalLiquidityReserves"
  ],
  "properties": {
    "totalLiquidityReserves": {
      "type": "array",
      "items": {
        "type": "object",
        "required": [
          "period",
          "liquidityReservesMillions"
        ],
        "properties": {
          "period": {
            "type": "string",
            "description": "Reporting period (e.g., '4Q19', '3Q23')"
          },
          "liquidityReservesMillions": {
            "type": "number",
            "description": "Total liquidity reserves in millions of USD for the period"
          }
        }
      },
      "description": "Total liquidity reserves in millions of USD for each reporting period"
    },
    "liquidityCoverageRatios": {
      "type": "array",
      "items": {
        "type": "object",
        "required": [
          "period",
          "lcrPercent"
        ],
        "properties": {
          "period": {
            "type": "string",
            "description": "Reporting period (e.g., '3Q23', '4Q23')"
          },
          "lcrPercent": {
            "type": "number",
            "description": "Decimal representation of the LCR percentage (e.g., 1.55 for 155%)"
          }
        }
      },
      "description": "Average quarterly LCR (Liquidity Coverage Ratio) over time"
    }
  }
}
